(window.webpackJsonp=window.webpackJsonp||[]).push([[349],{976:function(n,t){n.exports="\x3c!-- \ntitle: 10-Vue实战\nsort: \n--\x3e \n\n```bash\nnpm install -g vue-cli\nvue init webpack demo\n```\n\n## 步骤\n\n1. 编辑页面:  `/src/pages/Home.vue`\n\n\n```js\n<template>\n  <div>\n    <div class=\"title\">\n      <h1>{{ msg }}</h1>\n    </div>\n  </div>\n</template>\n\n<script>\nexport default {\n  name: 'home',\n  data () {\n    return {\n      msg: 'Welcome to Your Vue.js App'\n    }\n  }\n}\n<\/script>\n```\n\n2. 配置路由: `/src/router/index.js`\n\n```js\nimport Vue from 'vue'\nimport Router from 'vue-router'\nimport Home from '@/pages/Home'\n\nVue.use(Router)\n\nexport default new Router({\n  routes: [\n\t\t{\n      path: '/',\n      name: 'Home',\n      component: Home\n    }\n  ]\n})\n\n```\n\n3. 首页链接: `/src/app.vue`\n\n```vue\n<nav>\n  <div class=\"container\">\n    <ul class=\"nav_left\">\n      <li>\n        <router-link to=\"/\">Home</router-link>\n      </li>\n      <li>\n        <router-link to=\"/admin\">Admin</router-link>\n      </li>\n    </ul>\n  </div>\n</nav>\n```\n\n4. 编写组件: `/src/components/xx.vue`\n\n```vue\n<script>\nexport default {\n  name: 'product-list',\n  // 生命周期\n  created () {\n    if (this.products.length === 0) {\n      // 触发store的action\n      this.$store.dispatch('allProducts')\n    }\n  },\n  // 使用store传递参数\n  computed: {\n    products () {\n      // 取state\n      // return this.$store.state.products\n      // 调用action\n     \treturn this.$store.getters.allProducts\n    }\n  },\n  // 从父组件获得data\n  // props: ['model', 'manufacturers', 'isEditing'],\n  methods: {\n    // 触发父组件方法\n    saveProduct () {\n      // this.$emit('save-product', this.model)\n    },\n    // 触发Store的方法\n    addToCart (product) {\n      this.$store.commit('ADD_TO_CART', {\n        product\n      })\n    }\n  }\n}\n<\/script>\n```\n\n5. 编写Store: `/src/store/index.js`\n\n```js\nimport Vue from 'vue'\nimport Vuex from 'vuex'\nimport axios from 'axios'\n\nconst API_BASE = 'http://127.0.0.1:3000/api/v1/'\n\nVue.use(Vuex)\n\nexport default new Vuex.Store({\n  // 只有mutations能修改state的值\n  strict: true,\n  // 全部数据\n  state: {\n\t\tcart: [],\n    product: []\n  },\n  // 修改state值的函数\n  mutations: {\n    ADD_TO_CART (state, payload) {\n      const { product } = payload\n      state.cart.push(product)\n    },\n  },\n  // 异步操作\n  actions: {\n    allProducts ({ commit }) {\n      // 调用mutations\n      commit('ADD_TO_CART')\n\t\t\t// 发送异步请求\n      axios.get(`${API_BASE}/products`).then(response => {\n        console.log('response', response)\n        // 再次调用mutations\n        commit('ADD_TO_CART', {\n          products: response.data\n        })\n      })\n    }\n  }\n})\n```\n\n"}}]);